// Created: 2026-05-22

/**
 * Tests for pretool/settings-override-resolver — M168 Phase 4 (#1914).
 *
 * Verifies the resolver reads only the overrides for the current session
 * and snapshots them to ~/.claude/state/orchestkit/<sid>/active-overrides.json.
 * Critically: a different session's overrides must NOT appear in the file.
 */

import { describe, it, expect, beforeEach, afterEach } from 'vitest';
import { existsSync, mkdtempSync, readFileSync, rmSync } from 'node:fs';
import { tmpdir } from 'node:os';
import { join } from 'node:path';

import { settingsOverrideResolver, __internals } from '../../pretool/settings-override-resolver.js';
import { setOverride } from '../../lib/settings-override.js';
import { __resetDbForTests, openDb } from '../../lib/session-registry.js';
import { NOOP_CTX } from '../../lib/context.js';
import type { HookInput } from '../../types.js';

function makeInput(sid: string): HookInput {
  return {
    hook_event: 'PreToolUse',
    tool_name: 'Read',
    session_id: sid,
    tool_input: {},
  } as HookInput;
}

function seedSession(sid: string): void {
  const db = openDb();
  const now = Math.floor(Date.now() / 1000);
  db.prepare(
    `INSERT INTO sessions (sid, pid, cwd, repo_hash, repo_path, started_at, last_heartbeat, status)
     VALUES (?, 1, '/x', 'h', '/x', ?, ?, 'running')`,
  ).run(sid, now, now);
  db.close();
  __resetDbForTests();
}

describe('pretool/settings-override-resolver (#1914)', () => {
  let workDir: string;
  let prevDbEnv: string | undefined;
  let prevHome: string | undefined;

  beforeEach(() => {
    workDir = mkdtempSync(join(tmpdir(), 'ork-override-resolver-'));
    const dbPath = join(workDir, 'sessions.db');
    prevDbEnv = process.env.ORK_SESSION_DB;
    process.env.ORK_SESSION_DB = dbPath;
    // Redirect HOME so atomicWriteSync lands inside the fixture.
    prevHome = process.env.HOME;
    process.env.HOME = workDir;
    __resetDbForTests();
  });

  afterEach(() => {
    __resetDbForTests();
    if (prevDbEnv === undefined) delete process.env.ORK_SESSION_DB;
    else process.env.ORK_SESSION_DB = prevDbEnv;
    if (prevHome === undefined) delete process.env.HOME;
    else process.env.HOME = prevHome;
    rmSync(workDir, { recursive: true, force: true });
  });

  it('writes a snapshot containing only the current sid overrides', () => {
    seedSession('s-active');
    setOverride('s-active', 'effort', 'high');
    setOverride('s-active', 'model', 'claude-sonnet');

    const res = settingsOverrideResolver(makeInput('s-active'), NOOP_CTX);
    expect(res.continue).toBe(true);

    const path = __internals.snapshotPath('s-active');
    expect(existsSync(path)).toBe(true);

    const parsed = JSON.parse(readFileSync(path, 'utf8'));
    expect(parsed.sid).toBe('s-active');
    expect(typeof parsed.updated_at).toBe('number');
    const byKey = Object.fromEntries(
      (parsed.overrides as { key: string; value: string }[]).map(r => [r.key, r.value]),
    );
    expect(byKey).toEqual({ effort: 'high', model: 'claude-sonnet' });
  });

  it('isolates sessions — A reads A\'s overrides, never B\'s', () => {
    seedSession('s-a');
    seedSession('s-b');
    setOverride('s-a', 'effort', 'high');
    setOverride('s-b', 'effort', 'low');

    settingsOverrideResolver(makeInput('s-a'), NOOP_CTX);
    settingsOverrideResolver(makeInput('s-b'), NOOP_CTX);

    const snapA = JSON.parse(readFileSync(__internals.snapshotPath('s-a'), 'utf8'));
    const snapB = JSON.parse(readFileSync(__internals.snapshotPath('s-b'), 'utf8'));

    expect(snapA.overrides).toEqual([{ key: 'effort', value: 'high' }]);
    expect(snapB.overrides).toEqual([{ key: 'effort', value: 'low' }]);
  });

  it('writes an empty snapshot when no overrides exist', () => {
    seedSession('s-empty');
    settingsOverrideResolver(makeInput('s-empty'), NOOP_CTX);

    const path = __internals.snapshotPath('s-empty');
    expect(existsSync(path)).toBe(true);
    const parsed = JSON.parse(readFileSync(path, 'utf8'));
    expect(parsed.overrides).toEqual([]);
    expect(parsed.sid).toBe('s-empty');
  });

  it('is a no-op when session_id is missing', () => {
    const input = {
      hook_event: 'PreToolUse',
      tool_name: 'Read',
      session_id: '',
      tool_input: {},
    } as HookInput;
    const res = settingsOverrideResolver(input, NOOP_CTX);
    expect(res.continue).toBe(true);
    // Snapshot for "" should not be created.
    expect(existsSync(__internals.snapshotPath(''))).toBe(false);
  });

  it('overwrites a prior snapshot when overrides change', () => {
    seedSession('s-revise');
    setOverride('s-revise', 'effort', 'high');
    settingsOverrideResolver(makeInput('s-revise'), NOOP_CTX);

    setOverride('s-revise', 'effort', 'low');
    settingsOverrideResolver(makeInput('s-revise'), NOOP_CTX);

    const parsed = JSON.parse(readFileSync(__internals.snapshotPath('s-revise'), 'utf8'));
    expect(parsed.overrides).toEqual([{ key: 'effort', value: 'low' }]);
  });
});
